   803→/* send a command */
   804→static int azx_corb_send_cmd(struct hda_bus *bus, u32 val)
   805→{
   806→	struct azx *chip = bus->private_data;
   807→	unsigned int addr = azx_command_addr(val);
   808→	unsigned int wp;
   809→
   810→	spin_lock_irq(&chip->reg_lock);
   811→
   812→	/* add command to corb */
   813→	wp = azx_readb(chip, CORBWP);
   814→	wp++;
   815→	wp %= ICH6_MAX_CORB_ENTRIES;
   816→
   817→	chip->rirb.cmds[addr]++;
   818→	chip->corb.buf[wp] = cpu_to_le32(val);
   819→	azx_writel(chip, CORBWP, wp);
   820→
   821→	spin_unlock_irq(&chip->reg_lock);
   822→
   823→	return 0;
   824→}
