   828→/* retrieve RIRB entry - called from interrupt handler */
   829→static void azx_update_rirb(struct azx *chip)
   830→{
   831→	unsigned int rp, wp;
   832→	unsigned int addr;
   833→	u32 res, res_ex;
   834→
   835→	wp = azx_readb(chip, RIRBWP);
   836→	if (wp == chip->rirb.wp)
   837→		return;
   838→	chip->rirb.wp = wp;
   839→
   840→	while (chip->rirb.rp != wp) {
   841→		chip->rirb.rp++;
   842→		chip->rirb.rp %= ICH6_MAX_RIRB_ENTRIES;
